import { createNestablePublicClientApplication } from "@azure/msal-browser";

const CLIENT_ID = "72c1b54e-796b-4e6b-aa89-1f85502cc6b9";
const GRAPH_BASE = "https://graph.microsoft.com/v1.0";
let msalInstance = null;

async function initMsal() {
  if (msalInstance) return msalInstance;
  msalInstance = await createNestablePublicClientApplication({
    auth: { clientId: CLIENT_ID, authority: "https://login.microsoftonline.com/common" },
    cache: { cacheLocation: "localStorage" },
  });
  return msalInstance;
}

async function getToken(scopes) {
  const msal = await initMsal();
  try {
    const res = await msal.acquireTokenSilent({ scopes });
    return res.accessToken;
  } catch (e) {
    const res = await msal.acquireTokenPopup({ scopes });
    return res.accessToken;
  }
}

async function graphFetch(url, options) {
  const token = await getToken(["Mail.ReadWrite"]);
  const res = await fetch(GRAPH_BASE + url, {
    ...options,
    headers: { Authorization: "Bearer " + token, "Content-Type": "application/json", ...(options && options.headers) },
  });
  if (!res.ok) {
    const err = await res.text();
    throw new Error("Graph " + res.status + ": " + err);
  }
  if (res.status === 204) return null;
  return res.json();
}

// Convert Office.js EWS item ID to a Graph-compatible immutable ID
// Office desktop Outlook uses EWS-format IDs; Graph API needs REST IDs.
// The translateExchangeIds endpoint handles this conversion.
async function toGraphId(ewsId) {
  const result = await graphFetch("/me/translateExchangeIds", {
    method: "POST",
    body: JSON.stringify({
      inputIds: [ewsId],
      sourceIdType: "ewsId",
      targetIdType: "restId",
    }),
  });
  if (result && result.value && result.value[0]) return result.value[0].targetId;
  throw new Error("Could not translate ID");
}

// Resolve a message ID to Graph-compatible format (handles both REST and EWS)
async function resolveGraphId(messageId) {
  // Try direct first (REST IDs work as-is)
  try {
    await graphFetch("/me/messages/" + messageId + "?$select=id");
    return messageId;
  } catch (e) {
    // Fall back to EWS→REST translation
    return toGraphId(messageId);
  }
}

// Update categories on any message (not just the selected one)
async function graphSetCategories(messageId, categories) {
  const graphId = await resolveGraphId(messageId);
  return graphFetch("/me/messages/" + graphId, {
    method: "PATCH",
    body: JSON.stringify({ categories }),
  });
}

// Clear categories from ALL messages in a conversation
async function graphClearConversationCategories(conversationId) {
  if (!conversationId) return;
  const cats = ["High", "MedHigh", "MedLow", "Med", "Low", "Discuss", "Waiting", "Delegate"];
  var safeId = conversationId.replace(/'/g, "''");
  const filter = "conversationId eq '" + safeId + "' and (" + cats.map(c => "categories/any(a:a eq '" + c + "')").join(" or ") + ")";
  const result = await graphFetch(
    "/me/messages?$filter=" + encodeURIComponent(filter) +
    "&$select=id,categories&$top=50"
  );
  if (!result || !result.value) return;
  for (const msg of result.value) {
    await graphFetch("/me/messages/" + msg.id, {
      method: "PATCH",
      body: JSON.stringify({ categories: [] }),
    });
  }
}

// Move message to archive folder
async function graphArchiveMessage(messageId) {
  const graphId = await resolveGraphId(messageId);
  return graphFetch("/me/messages/" + graphId + "/move", {
    method: "POST",
    body: JSON.stringify({ destinationId: "archive" }),
  });
}

// Scan inbox for messages with task categories
async function graphScanCategorizedEmails() {
  const cats = ["High", "MedHigh", "MedLow", "Med", "Low", "Discuss", "Waiting", "Delegate"];
  const filter = cats.map(c => "categories/any(a:a eq '" + c + "')").join(" or ");
  const result = await graphFetch(
    "/me/mailFolders/inbox/messages?$filter=" +
      encodeURIComponent(filter) +
      "&$select=id,subject,receivedDateTime,categories,conversationId,from" +
      "&$orderby=receivedDateTime desc&$top=50"
  );
  return result && result.value ? result.value : [];
}

// Fetch sender name for a message — handles both REST and EWS id formats
async function graphGetSender(messageId) {
  // Try direct (REST ID) first
  try {
    const result = await graphFetch("/me/messages/" + messageId + "?$select=from");
    if (result && result.from && result.from.emailAddress) return result.from.emailAddress.name || "";
  } catch (e) {
    // If direct fails, try converting from EWS ID
    try {
      const graphId = await toGraphId(messageId);
      const result = await graphFetch("/me/messages/" + graphId + "?$select=from");
      if (result && result.from && result.from.emailAddress) return result.from.emailAddress.name || "";
    } catch (e2) {}
  }
  return "";
}

// Get all messages in a conversation thread (for AI summary context)
async function graphGetConversationMessages(conversationId) {
  if (!conversationId) return [];
  try {
    var safeId = conversationId.replace(/'/g, "''");
    const result = await graphFetch(
      "/me/messages?$filter=" + encodeURIComponent("conversationId eq '" + safeId + "'") +
      "&$select=from,body,receivedDateTime&$top=10&$orderby=receivedDateTime asc" +
      "&$expand=&prefer=outlook.body-content-type=\"text\""
    );
    if (!result || !result.value) return [];
    return result.value.map(m => ({
      from: m.from && m.from.emailAddress ? m.from.emailAddress.name || m.from.emailAddress.address : "Unknown",
      body: m.body && m.body.content ? m.body.content.substring(0, 500) : "",
      date: m.receivedDateTime || ""
    }));
  } catch (e) {
    console.log("Conversation fetch error:", e);
    return [];
  }
}

// Archive all messages in a conversation (moves all from inbox to archive)
async function graphArchiveConversation(conversationId) {
  if (!conversationId) return;
  var safeId = conversationId.replace(/'/g, "''");
  // Search inbox for messages in this conversation
  var result = null;
  try {
    result = await graphFetch(
      "/me/mailFolders/inbox/messages?$filter=" +
      encodeURIComponent("conversationId eq '" + safeId + "'") +
      "&$select=id&$top=50"
    );
  } catch (e) {
    console.log("Conversation query failed, trying all messages:", e);
    // Fallback: search all messages (not just inbox)
    try {
      result = await graphFetch(
        "/me/messages?$filter=" +
        encodeURIComponent("conversationId eq '" + safeId + "'") +
        "&$select=id,parentFolderId&$top=50"
      );
    } catch (e2) {
      console.log("All-messages query also failed:", e2);
      throw e2;
    }
  }
  if (!result || !result.value || result.value.length === 0) return;
  var moved = 0;
  for (const msg of result.value) {
    try {
      await graphFetch("/me/messages/" + msg.id + "/move", {
        method: "POST",
        body: JSON.stringify({ destinationId: "archive" }),
      });
      moved++;
    } catch (e) {
      console.log("Archive msg error:", e);
    }
  }
  console.log("Archived " + moved + "/" + result.value.length + " messages");
}

// Resolve Graph-format conversationId from a message ID (handles EWS→REST conversion)
// Office.js on desktop returns EWS-format conversationId which may not match Graph API filters.
// This fetches the message from Graph to get the canonical conversationId.
async function graphResolveConversationId(messageId) {
  if (!messageId) return null;
  try {
    const graphId = await resolveGraphId(messageId);
    const result = await graphFetch("/me/messages/" + graphId + "?$select=conversationId");
    return result && result.conversationId ? result.conversationId : null;
  } catch (e) {
    console.log("resolveConversationId error:", e);
    return null;
  }
}

// Check if Craig already replied/forwarded about this subject (searches Sent Items)
async function graphCheckSentReplies(subject) {
  if (!subject) return [];
  try {
    // Strip RE:/FW: prefixes to get the core subject
    var clean = subject.replace(/^(RE:|FW:|Fwd:)\s*/gi, "").trim();
    if (clean.length < 5) return [];
    // Strip KQL special chars: hyphens (NOT operator), quotes, colons
    var searchTerm = clean.replace(/['":\-]/g, " ").replace(/\s+/g, " ").trim();
    if (searchTerm.length < 5) return [];
    // $search cannot be combined with $orderby in Graph API
    // Outer quotes must be literal (not encoded) per OData $search spec
    var result = await graphFetch(
      '/me/mailFolders/sentitems/messages?$search="subject:' +
      encodeURIComponent(searchTerm) +
      '"&$select=toRecipients,sentDateTime,subject&$top=5'
    );
    var items = result && result.value ? result.value : [];
    // Post-filter: $search is fuzzy, so verify subjects actually match
    var cleanLower = clean.toLowerCase();
    return items.filter(function(msg) {
      if (!msg.subject) return false;
      var msgClean = msg.subject.replace(/^(RE:|FW:|Fwd:)\s*/gi, "").trim().toLowerCase();
      return msgClean.indexOf(cleanLower) !== -1 || cleanLower.indexOf(msgClean) !== -1;
    });
  } catch (e) {
    console.log("checkSentReplies error:", e);
    return [];
  }
}

// Expose all Graph functions on window for use by inline script in taskpane.html
window.k92Graph = {
  init: initMsal,
  setCategories: graphSetCategories,
  clearConversationCategories: graphClearConversationCategories,
  archiveMessage: graphArchiveMessage,
  archiveConversation: graphArchiveConversation,
  scanCategorizedEmails: graphScanCategorizedEmails,
  getSender: graphGetSender,
  getConversationMessages: graphGetConversationMessages,
  resolveConversationId: graphResolveConversationId,
  checkSentReplies: graphCheckSentReplies,
};
